const e = items[0].json;
const exec = e.execution || {};
const wf = e.workflow || {};
const lastNode = e.execution?.lastNodeExecuted || e.lastNodeExecuted || 'unknown';
const errMsg = e.execution?.error?.message || e.message || e.error?.message || JSON.stringify(e).slice(0, 800);
const workflowName = wf.name || e.workflow?.name || 'unknown_workflow';
const executionId = exec.id || e.executionId || null;

return [{
  json: {
    agent_name: workflowName,
    action_type: 'workflow_error',
    entity_type: 'workflow_execution',
    entity_id: null,
    result: 'failed',
    error_message: String(errMsg).slice(0, 2000),
    payload: {
      workflow_name: workflowName,
      workflow_id: wf.id || null,
      execution_id: executionId,
      last_node: lastNode,
      mode: e.mode || null
    }
  }
}];

